exec rs_rptCustomersDebtComparisonBook @tu_ngay, @den_ngay, null, null, @tk, @ma_kh, @nh_kh1, @nh_kh2, @nh_kh3, @ma_dvcs, @@language, @@userID, @@admin







      &OutlineEntry;
